@AccessControl.authorizationCheck: #CHECK

@EndUserText.label: 'Supplier - Interface View'

@Metadata.allowExtensions: true

@ObjectModel.usageType: { serviceQuality: #C, sizeCategory: #XL, dataClass: #MASTER }

define root view entity ZI_Supplier
  as select from I_BusinessPartnerSupplier as Supplier

{
  key Supplier.Supplier,
  key Supplier.BusinessPartner,

      Supplier.BusinessPartnerCategory,
      Supplier.SupplierAccountGroup,
      Supplier.Customer,
      Supplier.PostingIsBlocked,
      Supplier.PurchasingIsBlocked,
      Supplier.PaymentIsBlockedForSupplier,
      Supplier.DeletionIndicator,
      Supplier.SupplierCorporateGroup,
      Supplier.AuthorizationGroup,
      Supplier.VATLiability,
      Supplier.IsBusinessPurposeCompleted,
      Supplier.ReferenceAccountGroup,

      /* Business Partner fields via path expression */
      Supplier._BusinessPartner.BusinessPartnerName,
      Supplier._BusinessPartner.OrganizationBPName1,
      Supplier._BusinessPartner.SearchTerm1,
      Supplier._BusinessPartner.Industry,

      /* Associations */
      Supplier._BusinessPartner             as _BusinessPartner
}
